// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'NN_04_Telegram_Sender', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === CHAT_ID VALIDATION ===
let chat_id;
if (input.chat_id === undefined || input.chat_id === null) {
  return ve('MISSING_FIELD', 'chat_id is required');
}
if (typeof input.chat_id === 'string') {
  const trimmed = input.chat_id.trim();
  const INT_RE = /^\d+$/;
  if (!INT_RE.test(trimmed)) return ve('INVALID_TYPE', 'chat_id must be a positive integer');
  chat_id = parseInt(trimmed);
} else if (typeof input.chat_id === 'number') {
  chat_id = input.chat_id;
  if (!Number.isInteger(chat_id) || chat_id < 1) return ve('INVALID_TYPE', 'chat_id must be a positive integer');
} else {
  return ve('INVALID_TYPE', 'chat_id must be a number or numeric string');
}

// === TEXT VALIDATION ===
let text = null;
if (input.text !== undefined && input.text !== null) {
  text = String(input.text).trim();
} else if (input.ai_response !== undefined && input.ai_response !== null) {
  text = String(input.ai_response).trim();
}
if (!text || text.length === 0) return ve('MISSING_FIELD', 'text or ai_response is required');
if (text.length > 4096) return ve('INVALID_INPUT', 'text must be <= 4096 characters (Telegram limit)');

return [{ json: {
  success: true,
  chat_id,
  text,
  _validated: true
}}];

// Sanitize text for Telegram MarkdownV2 [SEC_02]
const input = $input.first().json;

// Pass-through validation errors
if (input._exit_early) {
  return [{ json: { ...input, sanitized_text: '' } }];
}

const text = input.text || '';
const sanitized = text.replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\$1');

return [{ json: {
  ...input,
  sanitized_text: sanitized
}}];

// GATE: Only process items with _validated === true
const input = $input.first().json;

if (input._exit_early) {
  return [];
}

return [{ json: input }];

// Handle Telegram API error
const e = $input.first().json;
const upstreamData = $('Pass Through Error').isExecuted ? $('Pass Through Error').first().json : {};
let error_code = 'TELEGRAM_API_ERROR';
let error_message = e.message || e.error?.message || 'Telegram API error';

if (error_message.includes('chat not found') || error_message.includes('400')) {
  error_code = 'TELEGRAM_CHAT_NOT_FOUND';
  error_message = 'Telegram chat not found or bot blocked';
} else if (error_message.includes('unauthorized') || error_message.includes('401')) {
  error_code = 'TELEGRAM_AUTH_ERROR';
  error_message = 'Telegram bot token invalid or revoked';
} else if (error_message.includes('rate limit') || error_message.includes('429')) {
  error_code = 'TELEGRAM_RATE_LIMIT';
  error_message = 'Telegram rate limit exceeded';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'NN_04_Telegram_Sender', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Format success — message sent
const result = $input.first().json;
const upstreamData = $('Pass Through Error').isExecuted ? $('Pass Through Error').first().json : {};

const msgId = result.result?.message_id || result.message_id || null;
const chatId = result.result?.chat?.id || result.chat?.id || upstreamData.chat_id || null;
const isSuccess = !!(msgId || result.ok === true) && !result.error;

if (!isSuccess) {
  return [{ json: {
    success: false, error_code: 'TELEGRAM_SEND_ERROR',
    error_message: 'Telegram returned success but no message_id',
    data: null,
    _meta: { source: 'NN_04_Telegram_Sender', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

return [{ json: {
  success: true, error_code: null, error_message: null,
  data: {
    message_id: msgId,
    chat_id: chatId,
    delivery_status: 'SENT',
    text_length: upstreamData.sanitized_text?.length || 0
  },
  _meta: {
    source: 'NN_04_Telegram_Sender',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const input = $input.first().json;

if (input.data !== undefined || input.error_code !== undefined) {
  return [{ json: {
    success: input.success === true,
    error_code: input.error_code || null,
    error_message: input.error_message || null,
    data: input.data || null,
    _meta: input._meta || {
      source: 'NN_04_Telegram_Sender',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }}];
}

return [];
